sql:
SELECT COUNT(DISTINCT instrument_id) AS Count
FROM market_data
WHERE close_price > (
    SELECT AVG(close_price) AS avg_close
    FROM market_data
);

SELECT sentiment_score 
FROM news_sentiments 
WHERE news_sentiment_id = 567;

SELECT instrument_id, AVG(sentiment_score) AS average_sentiment_score
FROM news_sentiments
GROUP BY instrument_id;

